 }

+/// Check if a range check is implied by a masked equality check.
+/// For (RangePred V, N) & (ICMP_EQ (and V, Mask), C), check if all values
+/// satisfying (V & Mask) == C also satisfy the range check. If so, return
+/// the masked equality (the more restrictive condition).
+static Value *foldRangeImpliedByMaskedEq(ICmpInst *RangeCmp, ICmpInst *MaskedEq,
+                                         bool IsAnd,
+                                         InstCombiner::BuilderTy &Builder) {
+  // Only handle AND for now
+  if (!IsAnd)
+    return nullptr;
+
+  // RangeCmp should be a range check: ult, ule, ugt, uge, slt, sle, sgt, sge
+  ICmpInst::Predicate RangePred = RangeCmp->getPredicate();
+  // Accept all relational predicates (not equality predicates)
+  if (ICmpInst::isEquality(RangePred))
+    return nullptr;
+
+  // MaskedEq should be (icmp eq (and V, Mask), C)
+  Value *MaskedOp0;
+  const APInt *C;
+  if (!match(MaskedEq, m_ICmp(m_Value(MaskedOp0), m_APInt(C))))
+    return nullptr;
+  if (MaskedEq->getPredicate() != ICmpInst::ICMP_EQ)
+    return nullptr;
+  const APInt *Mask;
+  Value *V;
+  if (!match(MaskedOp0, m_And(m_Value(V), m_APInt(Mask))))
+    return nullptr;
+
+  // RangeCmp should be (icmp RangePred V2, N) where V2 is the same as V
+  Value *RangeV;
+  const APInt *N;
+  if (!match(RangeCmp, m_ICmp(m_Value(RangeV), m_APInt(N))))
+    return nullptr;
+  if (RangeCmp->getPredicate() != RangePred)
+    return nullptr;
+  if (RangeV != V)
+    return nullptr;
+
+  // The values satisfying (V & Mask) == C are: C | X where X & Mask == 0
+  // Min value: C (all bits in ~Mask set to 0)
+  // Max value: C | ~Mask (all bits in ~Mask set to 1)
+  APInt NotMask = ~*Mask;
+  APInt MinVal = *C;
+  APInt MaxVal = *C | NotMask;
+
+  // Check if the range condition is always satisfied
+  bool AlwaysTrue = false;
+  
+  switch (RangePred) {
+  case ICmpInst::ICMP_ULT:
+    AlwaysTrue = MaxVal.ult(*N);
+    break;
+  case ICmpInst::ICMP_ULE:
+    AlwaysTrue = MaxVal.ule(*N);
+    break;
+  case ICmpInst::ICMP_UGT:
+    AlwaysTrue = MinVal.ugt(*N);
+    break;
+  case ICmpInst::ICMP_UGE:
+    AlwaysTrue = MinVal.uge(*N);
+    break;
+  case ICmpInst::ICMP_SLT:
+    AlwaysTrue = MaxVal.slt(*N);
+    break;
+  case ICmpInst::ICMP_SLE:
+    AlwaysTrue = MaxVal.sle(*N);
+    break;
+  case ICmpInst::ICMP_SGT:
+    AlwaysTrue = MinVal.sgt(*N);
+    break;
+  case ICmpInst::ICMP_SGE:
+    AlwaysTrue = MinVal.sge(*N);
+    break;
+  default:
+    return nullptr;
+  }
+
+  if (!AlwaysTrue)
+    return nullptr;
+
+  // The range check is always true when the masked equality is true.
+  // Return the masked equality.
+  return MaskedEq;
+}
+
 /// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
 /// If IsLogical is true, then the and/or is in select form and the transform
 /// must be poison-safe.
@@ -3442,6 +3528,14 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return V;
   }

+  // Check if range check is implied by masked equality
+  if (!IsLogical) {
+    if (Value *V = foldRangeImpliedByMaskedEq(LHS, RHS, IsAnd, Builder))
+      return V;
+    if (Value *V = foldRangeImpliedByMaskedEq(RHS, LHS, IsAnd, Builder))
+      return V;
+  }
+
   // TODO: Add conjugated or fold, check whether it is safe for logical and/or.
   if (IsAnd && !IsLogical)
     if (Value *V = foldSignedTruncationCheck(LHS, RHS, I, Builder))

